+unsafe fn raw_clock_gettime(clock_id: c_int, tp: *mut libc::timespec) -> c_int {
+    if vdso_clock_supported(clock_id) {
+        let symbols = *VDSO_SYMBOLS.get_or_init(resolve_vdso_symbols);
